records = [
  {"id":"inno_ent_201","name_ja":"シリコンバレー起業家エコシステム","name_en":"Silicon Valley Entrepreneurial Ecosystem","definition":"カリフォルニア州サンタクララバレーを中心に形成された世界最大規模の起業家エコシステム。スタンフォード大学、VCネットワーク、人材流動性、文化的失敗許容度が高密度に集積し、Google、Apple、Intel等を輩出した。AnnaLee Saxenianらが比較研究を通じてその構造的優位性を分析した。","impact_summary":"世界の起業家エコシステムモデルの原型として、各国の政策立案に影響を与えた。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":1970,"schumpeter_layer":"ミクロ","innovation_type":"組織・制度イノベーション","cognitive_mechanism":"社会的学習と知識スピルオーバー","key_researchers":["AnnaLee Saxenian","Martin Kenney","Richard Florida"],"key_works":["Regional Advantage (1994)","Silicon Valley Edge (2000)"],"keywords_ja":"シリコンバレー,起業家エコシステム,VC,スタンフォード大学","keywords_en":"Silicon Valley,entrepreneurial ecosystem,venture capital,Stanford"},
  {"id":"inno_ent_202","name_ja":"イスラエル・スタートアップネーション","name_en":"Israel Startup Nation Phenomenon","definition":"人口900万人のイスラエルがナスダック上場企業数で世界第3位に達した現象。軍事技術開発（特にUnit 8200）、移民起業家、政府R&D補助金（OCS）、失敗許容文化の組み合わせが独自の起業家エコシステムを形成した。Dan SenorとSaul Singerが「Start-Up Nation」で詳細に分析した。","impact_summary":"小国が技術起業家精神で世界的地位を確立できることを示し、多国の政策参照モデルとなった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"国家イノベーションシステム論","era_start":1990,"schumpeter_layer":"メゾ","innovation_type":"制度イノベーション","cognitive_mechanism":"軍事技術の民間転用と移民多様性","key_researchers":["Dan Senor","Saul Singer","Yozma Program researchers"],"key_works":["Start-Up Nation (2009)","Yozma Program Evaluation"],"keywords_ja":"イスラエル,スタートアップ,軍事技術移転,Unit 8200","keywords_en":"Israel,startup nation,military technology transfer,innovation ecosystem"},
  {"id":"inno_ent_203","name_ja":"中国起業家精神と深圳モデル","name_en":"Chinese Entrepreneurship and Shenzhen Model","definition":"1980年代の経済特区設立から始まり、深圳が「世界のハードウェアシリコンバレー」へと発展したプロセス。山寨文化（模倣から創造へ）、供給チェーン集積、政府主導インキュベーションが融合した独自の起業家モデルを形成した。Bunnie Huangや田涛らの研究が深圳エコシステムを詳細に記述した。","impact_summary":"製造業ベースの起業家エコシステムという新類型を提示し、グローバルサウスのモデルとなった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"比較起業家論","era_start":1980,"schumpeter_layer":"メゾ","innovation_type":"プロセスイノベーション","cognitive_mechanism":"模倣から創造への学習転換","key_researchers":["Bunnie Huang","田涛","Mary Ann O'Donnell"],"key_works":["Shenzhen: The Silicon Valley of Hardware (2016)","Factory Girls (2008)"],"keywords_ja":"深圳,山寨,ハードウェアスタートアップ,中国起業家精神","keywords_en":"Shenzhen,shanzhai,hardware startup,Chinese entrepreneurship"},
  {"id":"inno_ent_204","name_ja":"インド起業家精神とバンガロールモデル","name_en":"Indian Entrepreneurship and Bangalore IT Model","definition":"インド工科大学（IIT）卒業生を中核とし、バンガロールを拠点に形成されたITアウトソーシングから製品開発への転換プロセス。Diaspora起業家（帰国移民）、政府のIT優遇政策、英語教育の優位性が複合的に作用した。Vivek Wadhwaらが移民起業家の役割を実証的に分析した。","impact_summary":"教育投資と移民ネットワークを通じた後発国の技術起業家精神確立モデルを提示した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"移民起業家論","era_start":1991,"schumpeter_layer":"メゾ","innovation_type":"サービスイノベーション","cognitive_mechanism":"Diaspora知識移転と逆移民","key_researchers":["Vivek Wadhwa","AnnaLee Saxenian","Rafiq Dossani"],"key_works":["The Immigrant Exodus (2012)","Silicon Valley's New Immigrant Entrepreneurs (1999)"],"keywords_ja":"インド,バンガロール,IIT,移民起業家,IT産業","keywords_en":"India,Bangalore,IIT,diaspora entrepreneurship,IT industry"},
  {"id":"inno_ent_205","name_ja":"北欧起業家精神とノルディックモデル","name_en":"Nordic Entrepreneurship and Nordic Model","definition":"フィンランド、スウェーデン、デンマーク等北欧諸国における高福祉・高起業率の共存現象。社会的セーフティネットによる失敗リスク低下、高品質教育、フラットな組織文化、オープンソース文化が起業家精神を育む独自モデルを形成した。Nokiaの興隆と衰退から生まれた第二世代起業家（Rovio、Supercell等）が象徴的事例。","impact_summary":"福祉国家と起業家精神は両立可能という命題を実証し、政策設計の参照モデルとなった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"比較制度論","era_start":1995,"schumpeter_layer":"メゾ","innovation_type":"社会制度イノベーション","cognitive_mechanism":"リスク許容度の制度的支援","key_researchers":["Erkko Autio","Pekka Ylä-Anttila","Bengt-Åke Lundvall"],"key_works":["Nordic Entrepreneurship Research (2007)","Nokia: The Inside Story (2001)"],"keywords_ja":"北欧,フィンランド,起業家精神,福祉国家,Nokia","keywords_en":"Nordic,Finland,entrepreneurship,welfare state,Nokia effect"},
  {"id":"inno_ent_206","name_ja":"日本の起業家精神の課題と再生","name_en":"Japanese Entrepreneurship Challenges and Revival","definition":"日本の起業率が先進国最低水準（約5%）に留まる構造的要因と、2010年代以降の再活性化動向の研究領域。終身雇用制度、失敗への社会的スティグマ、間接金融優位、規制環境が起業障壁として機能してきたが、経産省のJ-Startup政策、スタートアップエコシステム拠点都市形成戦略が転換を図っている。","impact_summary":"起業家精神の文化的・制度的障壁の分析を通じ、政策介入の方向性を示した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"制度的起業家論","era_start":2013,"schumpeter_layer":"メゾ","innovation_type":"制度イノベーション","cognitive_mechanism":"制度的慣性と変革への抵抗","key_researchers":["藤田誠","山本勲","経済産業研究所研究者"],"key_works":["日本のスタートアップ研究 (2020)","J-Startup政策評価報告 (2022)"],"keywords_ja":"日本,起業家精神,起業率,J-Startup,制度障壁","keywords_en":"Japan,entrepreneurship,startup ecosystem,J-Startup,institutional barriers"},
  {"id":"inno_ent_207","name_ja":"GEM起業活動総合指数","name_en":"GEM Total Entrepreneurial Activity Index","definition":"Global Entrepreneurship Monitor（GEM）が測定するTEA（Total Early-Stage Entrepreneurial Activity）指数は、18-64歳人口のうち過去3年以内に創業した企業の経営者または起業準備中の割合を示す。1999年以来50カ国以上で継続測定され、機会主導型vs必要性主導型起業活動の区別を導入した比較研究の基盤データ。","impact_summary":"起業活動の国際比較を可能にし、各国政策立案の証拠基盤として広く活用されている。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":1999,"schumpeter_layer":"ミクロ","innovation_type":"測定・指標イノベーション","cognitive_mechanism":"起業意図から行動への転換メカニズム","key_researchers":["Paul Reynolds","Niels Bosma","Donna Kelley"],"key_works":["GEM Global Report (annual)","GEM 2000 Executive Report"],"keywords_ja":"GEM,TEA,起業活動,国際比較,機会起業","keywords_en":"GEM,TEA,entrepreneurial activity,international comparison,opportunity entrepreneurship"},
  {"id":"inno_ent_208","name_ja":"GEM起業家精神エコシステム条件","name_en":"GEM Entrepreneurial Framework Conditions","definition":"GEMが提唱する起業家精神を規定する9つのエコシステム条件：金融アクセス、政府政策、政府プログラム、起業家教育、R&D移転、商業・専門インフラ、内需市場開放性・規模・ダイナミクス、物理インフラ、文化・社会規範。これらの条件が国ごとに異なる起業率を説明する分析枠組みを提供する。","impact_summary":"起業家精神の多次元的決定要因を体系化し、政策介入点を特定する枠組みとして機能した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"エコシステム論","era_start":1999,"schumpeter_layer":"メゾ","innovation_type":"分析枠組み","cognitive_mechanism":"環境条件と起業行動の相互作用","key_researchers":["Michael Hay","Zoltan Acs","Erkko Autio"],"key_works":["GEM Conceptual Model (1999)","Entrepreneurship in a Global Context (2016)"],"keywords_ja":"GEM,エコシステム条件,起業環境,政策","keywords_en":"GEM,entrepreneurial framework conditions,ecosystem,policy"},
  {"id":"inno_ent_209","name_ja":"GEM機会型vs必要型起業活動","name_en":"GEM Opportunity vs Necessity Entrepreneurship","definition":"GEMが導入した分類概念。機会型起業（opportunity entrepreneurship）は成長機会の認識から生まれ、必要型起業（necessity entrepreneurship）は他の就業機会がないために行われる。先進国では機会型が支配的で、発展途上国では必要型が高い傾向があり、この比率が経済発展段階の指標となる。","impact_summary":"起業の質的側面を捕捉する概念として、単純な起業率を超えた政策評価を可能にした。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":2001,"schumpeter_layer":"ミクロ","innovation_type":"概念的イノベーション","cognitive_mechanism":"動機と機会認識の相互作用","key_researchers":["Paul Reynolds","William Bygrave","Maria Minniti"],"key_works":["GEM 2001 Summary Report","Entrepreneurship and the Business Cycle (2008)"],"keywords_ja":"GEM,機会型起業,必要型起業,経済発展","keywords_en":"GEM,opportunity entrepreneurship,necessity entrepreneurship,economic development"},
  {"id":"inno_ent_210","name_ja":"起業家教育プログラム設計論","name_en":"Entrepreneurship Education Program Design","definition":"起業家精神を教育可能なスキルセットとして体系化し、カリキュラム・教授法・評価方法を設計する研究領域。Babson Collegeの「EMP（Entrepreneurship Management Program）」、MITのD-LabやMedia Lab、スタンフォードd.schoolが代表的プログラムを開発した。経験学習（Kolb）、プロジェクトベース学習、スタートアップシミュレーション等の手法が研究されている。","impact_summary":"起業家教育の標準化と普及を通じて、高等教育機関における起業家育成機能を確立した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家教育論","era_start":1985,"schumpeter_layer":"ミクロ","innovation_type":"教育イノベーション","cognitive_mechanism":"経験学習と起業的思考の形成","key_researchers":["William Bygrave","Julian Lange","Heidi Neck"],"key_works":["Entrepreneurship (2004)","Teaching Entrepreneurship (2014)"],"keywords_ja":"起業家教育,Babson,カリキュラム,経験学習","keywords_en":"entrepreneurship education,Babson,curriculum,experiential learning"},
  {"id":"inno_ent_211","name_ja":"リーンスタートアップ方法論","name_en":"Lean Startup Methodology","definition":"Eric Riesが提唱した起業プロセス方法論。「構築-測定-学習」のフィードバックループを最小化したMVP（Minimum Viable Product）によって仮説検証を繰り返す。顧客開発（Steve Blank）とアジャイル開発を統合し、不確実性下での効率的なイノベーション管理を実現する。2010年代以降スタートアップ界の標準的方法論となった。","impact_summary":"「スタートアップは大企業の縮小版ではない」という命題を普及させ、世界中のスタートアップ方法論を変革した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実践的起業家方法論","era_start":2011,"schumpeter_layer":"ミクロ","innovation_type":"プロセスイノベーション","cognitive_mechanism":"仮説-検証-反復による不確実性低減","key_researchers":["Eric Ries","Steve Blank","Alexander Osterwalder"],"key_works":["The Lean Startup (2011)","The Startup Owner's Manual (2012)"],"keywords_ja":"リーンスタートアップ,MVP,ピボット,仮説検証","keywords_en":"lean startup,MVP,pivot,hypothesis testing,build-measure-learn"},
  {"id":"inno_ent_212","name_ja":"顧客開発プロセス","name_en":"Customer Development Process","definition":"Steve Blankが提唱した4段階の顧客中心起業プロセス：顧客発見（customer discovery）→顧客実証（customer validation）→顧客創造（customer creation）→企業構築（company building）。製品開発と並行して顧客問題・ニーズを体系的に検証し、製品市場適合（PMF）を達成するまでピボットを繰り返す。","impact_summary":"B2Bスタートアップにおける体系的市場検証手法として広く採用され、Leanムーブメントの理論的基盤となった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実践的起業家方法論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"プロセスイノベーション","cognitive_mechanism":"顧客フィードバックによる製品仕様収束","key_researchers":["Steve Blank","Bob Dorf","Eric Ries"],"key_works":["The Four Steps to the Epiphany (2005)","The Startup Owner's Manual (2012)"],"keywords_ja":"顧客開発,PMF,ピボット,B2B起業","keywords_en":"customer development,PMF,pivot,startup process"},
  {"id":"inno_ent_213","name_ja":"ビジネスモデルキャンバス","name_en":"Business Model Canvas","definition":"Alexander OsterwalderとYves Pigneurが開発した9つの構成要素（顧客セグメント、価値提案、チャネル、顧客関係、収益の流れ、主要リソース、主要活動、主要パートナー、コスト構造）でビジネスモデルを可視化するツール。スタートアップから大企業まで広く使用され、ピボット前後のモデル比較や投資家向けコミュニケーションに活用される。","impact_summary":"ビジネスモデルの共通言語を提供し、起業家教育・コンサルティング・投資評価のデファクトスタンダードとなった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"ビジネスモデル論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"ツール・方法論イノベーション","cognitive_mechanism":"視覚的思考と構造化されたビジネス設計","key_researchers":["Alexander Osterwalder","Yves Pigneur","Steve Blank"],"key_works":["Business Model Generation (2010)","Value Proposition Design (2014)"],"keywords_ja":"ビジネスモデルキャンバス,価値提案,BMC","keywords_en":"business model canvas,value proposition,BMC,Osterwalder"},
  {"id":"inno_ent_214","name_ja":"エフェクチュエーション理論","name_en":"Effectuation Theory","definition":"Saras Sarasvathyが経験豊富な起業家の思考プロセスを研究して提唱した理論。「因果推論（causation）」が目標から手段を選ぶのに対し、「エフェクチュエーション」は利用可能な手段から達成可能な目標を創造する。許容可能な損失、鳥の手の原則、レモネード原則、クレイジーキルト原則の4原則からなる。","impact_summary":"起業家的思考の独自性を認識論的に定式化し、起業家教育と戦略研究に大きな影響を与えた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":2001,"schumpeter_layer":"ミクロ","innovation_type":"認知・行動イノベーション","cognitive_mechanism":"手段から目標への逆算的思考","key_researchers":["Saras Sarasvathy","Stuart Read","Nick Dew"],"key_works":["What Makes Entrepreneurs Entrepreneurial? (2001)","Effectuation (2008)"],"keywords_ja":"エフェクチュエーション,起業家的思考,許容損失,手段主導","keywords_en":"effectuation,entrepreneurial cognition,affordable loss,means-driven"},
  {"id":"inno_ent_215","name_ja":"起業プロセスの段階モデル","name_en":"Stage Models of Entrepreneurial Process","definition":"起業プロセスを離散的段階として記述するモデル群。Birleyの3段階（アイデア→資源調達→立上げ）、Shane & Venkataramanの機会認識→評価→活用モデル、GEMのナセント→新興→既存企業の区分等が代表的。各段階での失敗率、障壁、成功要因の分析を通じて支援介入の最適タイミングを特定する。","impact_summary":"起業支援政策の段階別設計を可能にし、インキュベーター・アクセラレーター設計の理論基盤となった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"プロセス理論","era_start":1994,"schumpeter_layer":"ミクロ","innovation_type":"分析枠組み","cognitive_mechanism":"段階的意思決定と資源蓄積","key_researchers":["Howard Aldrich","Scott Shane","Sankaran Venkataraman"],"key_works":["Organizations Evolving (1999)","A General Theory of Entrepreneurship (2003)"],"keywords_ja":"起業プロセス,段階モデル,ナセント起業家,機会活用","keywords_en":"entrepreneurial process,stage model,nascent entrepreneur,opportunity exploitation"},
  {"id":"inno_ent_216","name_ja":"シードステージVC投資","name_en":"Seed Stage Venture Capital Investment","definition":"スタートアップの最初期段階（製品プロトタイプ前後）への機関投資家による小額出資。典型的には50万〜300万ドル規模。AngelListの普及、マイクロVCの台頭、YCombinator等アクセラレーターによるデモデー後投資が主要ルート。投資判断基準はチーム・市場サイズ・プロダクト仮説の評価が中心。","impact_summary":"シード投資の機関化により初期スタートアップへの資本アクセスが民主化され、創業障壁が低下した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"VC論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"金融イノベーション","cognitive_mechanism":"不確実性下での信号検出と評価","key_researchers":["Paul Gompers","Josh Lerner","Aileen Lee"],"key_works":["The Venture Capital Cycle (2004)","Welcome to the Unicorn Club (2013)"],"keywords_ja":"シードVC,マイクロVC,AngelList,シード投資","keywords_en":"seed VC,micro VC,AngelList,seed investment"},
  {"id":"inno_ent_217","name_ja":"シリーズA〜C成長資金調達","name_en":"Series A to C Growth Financing","definition":"製品市場適合（PMF）達成後の成長加速を目的とした段階的VC調達ラウンド。シリーズAは典型的に200〜1500万ドル（チームと市場拡大への投資）、シリーズBは1500〜3000万ドル（スケール）、シリーズCは3000万ドル以上（グローバル展開）。各ラウンドの希薄化管理、ダウンラウンドリスク、優先株式の設計が重要課題となる。","impact_summary":"段階的資金調達の標準化により、スタートアップの成長軌道管理と投資家期待値の整合が進んだ。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"VC論","era_start":1980,"schumpeter_layer":"ミクロ","innovation_type":"金融イノベーション","cognitive_mechanism":"マイルストーン達成による信頼構築","key_researchers":["William Sahlman","Paul Gompers","Andrew Metrick"],"key_works":["How Venture Capital Works (1997)","Venture Capital and the Finance of Innovation (2007)"],"keywords_ja":"シリーズA,シリーズB,成長資金,希薄化,優先株","keywords_en":"Series A,Series B,growth financing,dilution,preferred stock"},
  {"id":"inno_ent_218","name_ja":"VCデューデリジェンスと評価手法","name_en":"VC Due Diligence and Valuation Methods","definition":"VCが投資判断前に実施する詳細調査プロセス。ビジネスモデル検証、チームバックグラウンドチェック、市場サイズ分析（TAM/SAM/SOM）、競合分析、知財確認、財務モデル評価を含む。評価手法としてはDiscounted Cash Flow（DCF）、比較会社分析、Venture Capital Method、Berkus Methodが用いられる。早期段階では定量的評価より定性的判断（チーム・ビジョン）の比重が高い。","impact_summary":"投資プロセスの標準化によりVC意思決定の一貫性が高まり、スタートアップの資金調達準備の明確化につながった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"VC論","era_start":1990,"schumpeter_layer":"ミクロ","innovation_type":"評価・判断イノベーション","cognitive_mechanism":"情報非対称性下での意思決定","key_researchers":["William Sahlman","Robert Higgins","James Plummer"],"key_works":["A Method for Valuing High-Risk, Long-Term Investments (1987)","Venture Capital at the Crossroads (1992)"],"keywords_ja":"デューデリジェンス,TAM,VC評価,Berkus Method","keywords_en":"due diligence,TAM,VC valuation,Berkus Method"},
  {"id":"inno_ent_219","name_ja":"VC投資家の選択基準と意思決定","name_en":"VC Investment Criteria and Decision-Making","definition":"VCが投資対象を選ぶ基準の実証的研究。MacMillan et al.（1985）の先駆的研究以来、「チームの質」が最重要基準として繰り返し確認されている。続いて市場規模・成長性、製品差別化、事業モデルの実行可能性の順に重視される。近年ではAIを活用したシグナル検出、LinkedInデータ分析、パターン認識による投資決定も研究されている。","impact_summary":"VC意思決定の実証的理解により、起業家がピッチ準備を最適化し、資金調達成功率を高める知見が蓄積された。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"VC論","era_start":1985,"schumpeter_layer":"ミクロ","innovation_type":"意思決定イノベーション","cognitive_mechanism":"ヒューリスティックと分析的判断の統合","key_researchers":["Ian MacMillan","David Brophy","Jeffry Timmons"],"key_works":["Criteria Used by Venture Capitalists (1985)","New Venture Creation (2003)"],"keywords_ja":"VC投資基準,チーム評価,市場サイズ,投資決定","keywords_en":"VC investment criteria,team evaluation,market size,investment decision"},
  {"id":"inno_ent_220","name_ja":"エンジェル投資家の行動と役割","name_en":"Angel Investor Behavior and Role","definition":"個人資産をもって初期段階スタートアップに直接投資する富裕個人（エンジェル）の研究。典型的投資規模は2.5万〜10万ドルで、VCより早い段階をカバーする。Jeffry Timmons、William Wetzelらが1980年代に概念化。ビジネスエンジェルは資金だけでなくメンタリング・ネットワーク・業界知見も提供する（スマートマネー）。AngelListの登場でエンジェル投資が民主化した。","impact_summary":"VC前の資金ギャップを埋め、スタートアップエコシステムの初期層を支える機能が実証された。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"VC論","era_start":1983,"schumpeter_layer":"ミクロ","innovation_type":"金融イノベーション","cognitive_mechanism":"同業者ネットワークと信頼ベースの投資判断","key_researchers":["William Wetzel","Jeffry Timmons","Robert Wiltbank"],"key_works":["Informal Risk Capital in New England (1983)","Returns to Angel Investors (2007)"],"keywords_ja":"エンジェル投資,スマートマネー,AngelList,初期投資","keywords_en":"angel investment,smart money,AngelList,early stage investment"},
  {"id":"inno_ent_221","name_ja":"エンジェル投資シンジケート","name_en":"Angel Investment Syndicates","definition":"複数のエンジェル投資家が共同で投資判断・資金拠出を行う形態。AngelList Syndicatesの普及（2013年〜）により、リード投資家が判断しバッカーが追随する仕組みが制度化された。リスク分散、デューデリジェンス効率化、より大規模な投資実行が可能になる。エンジェルグループ（Tech Coast Angels等）とオンラインシンジケートの2形態が存在する。","impact_summary":"個人エンジェルの投資能力を組織的に拡大し、シード以前の資金供給を厚くする機能を果たした。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"VC論","era_start":2013,"schumpeter_layer":"ミクロ","innovation_type":"金融組織イノベーション","cognitive_mechanism":"集合知による投資判断と情報カスケード","key_researchers":["Naval Ravikant","Robert Wiltbank","David Amis"],"key_works":["AngelList Syndicates (2013)","Winning Angels (2001)"],"keywords_ja":"エンジェルシンジケート,AngelList,リード投資家,集合投資","keywords_en":"angel syndicates,AngelList,lead investor,collective investment"},
  {"id":"inno_ent_222","name_ja":"報酬型クラウドファンディング","name_en":"Reward-Based Crowdfunding","definition":"Kickstarter（2009）、Indiegogo（2008）等のプラットフォームを通じ、製品・サービスの早期支援者に報酬（プレオーダー商品、特典等）を提供する資金調達形態。製品コンセプトの市場検証、プリセールスによる製造資金確保、コミュニティ形成を同時に達成できる。Oculus Rift、Pebble Watch等が代表的成功事例。","impact_summary":"消費者直結の事前市場検証を可能にし、ハードウェアスタートアップの資金調達モデルを変革した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"プラットフォーム論","era_start":2009,"schumpeter_layer":"ミクロ","innovation_type":"金融イノベーション","cognitive_mechanism":"社会的証明と群集動員","key_researchers":["Ethan Mollick","Ajay Agrawal","Avi Goldfarb"],"key_works":["The Dynamics of Crowdfunding (2014)","Crowdfunding: Geography, Social Networks (2015)"],"keywords_ja":"報酬型クラウドファンディング,Kickstarter,プレオーダー,市場検証","keywords_en":"reward crowdfunding,Kickstarter,pre-order,market validation"},
  {"id":"inno_ent_223","name_ja":"株式型クラウドファンディング","name_en":"Equity Crowdfunding","definition":"一般投資家がスタートアップの株式に小額から投資できる資金調達形態。米国JOBS Act（2012）、日本金融商品取引法改正（2015）等の規制緩和により制度化された。Crowdcube、Seedrs（英国）、Fundinno（日本）が代表的プラットフォーム。従来VCアクセスのなかった地方・女性・マイノリティ起業家への資本民主化が期待される一方、情報非対称性・投資家保護が課題。","impact_summary":"資本調達の民主化を促進し、スタートアップ投資家層を機関投資家から個人へと拡大した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"プラットフォーム論","era_start":2012,"schumpeter_layer":"ミクロ","innovation_type":"金融イノベーション","cognitive_mechanism":"情報開示と群集による企業評価","key_researchers":["Ethan Mollick","Sherwood Neiss","Jason Best"],"key_works":["Crowdfund Investing for Dummies (2013)","Equity Crowdfunding (2016)"],"keywords_ja":"株式型クラウドファンディング,JOBS Act,投資民主化,Fundinno","keywords_en":"equity crowdfunding,JOBS Act,investment democratization,securities"},
  {"id":"inno_ent_224","name_ja":"ICO（イニシャルコインオファリング）","name_en":"Initial Coin Offering","definition":"ブロックチェーンプロジェクトがトークン（暗号資産）を発行して資金を調達する仕組み。2017〜2018年のバブル期に急増し、総額200億ドル超の調達が実施された。規制の曖昧さと詐欺リスクが顕在化後、STOやIEOへ移行。分散型自律組織（DAO）と組み合わせたトークノミクス設計が新たな研究領域として発展した。","impact_summary":"ブロックチェーン・Web3領域の新たな資金調達形態を生み出し、規制サンドボックスと投資家保護の議論を促進した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"フィンテック・Web3論","era_start":2017,"schumpeter_layer":"ミクロ","innovation_type":"金融イノベーション","cognitive_mechanism":"トークンエコノミーと投機的期待","key_researchers":["Christian Catalini","Joshua Gans","Garrick Hileman"],"key_works":["Initial Coin Offerings and the Value of Crypto Tokens (2018)","Global Cryptocurrency Benchmarking Study (2017)"],"keywords_ja":"ICO,トークン,ブロックチェーン,Web3,資金調達","keywords_en":"ICO,token,blockchain,Web3,cryptocurrency fundraising"},
  {"id":"inno_ent_225","name_ja":"SPAC（特別目的買収会社）","name_en":"Special Purpose Acquisition Company","definition":"上場を目的として設立される空箱会社。IPO後2年以内に非上場企業と合併することでターゲット企業を上場させる。2020〜2021年に急増し、米国上場件数の過半を占めた。従来のIPOより迅速・低コストで上場できる一方、希薄化リスクと投資家保護の問題が指摘され、2022年以降SEC規制強化。ユニコーンの代替上場ルートとして研究されている。","impact_summary":"スタートアップの上場経路を多様化し、未公開株投資家と公開市場の接点を拡大した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"コーポレートファイナンス論","era_start":2020,"schumpeter_layer":"ミクロ","innovation_type":"金融イノベーション","cognitive_mechanism":"迂回上場と情報開示の非対称性","key_researchers":["Michael Klausner","Usha Rodrigues","Michael Ohlrogge"],"key_works":["A Sober Look at SPACs (2020)","SPAC Law and Myths (2021)"],"keywords_ja":"SPAC,空箱上場,デスパック,IPO代替","keywords_en":"SPAC,blank check company,de-SPAC,alternative IPO"},
  {"id":"inno_ent_226","name_ja":"Y Combinatorモデル","name_en":"Y Combinator Accelerator Model","definition":"Paul Graham、Jessica Livingston、Robert Morris、Trevor Blackwellが2005年に設立したシリコンバレーのシードアクセラレーター。3ヶ月のバッチプログラムで少額投資（現在12.5万ドル）＋デモデーのモデルを確立した。Airbnb、Dropbox、Stripe等を輩出。「Make something people want」「Do things that don't scale」等の原則で知られ、卒業生ネットワークが強力な資産となっている。","impact_summary":"アクセラレーターモデルを世界に普及させ、スタートアップ支援の主要形態として定着させた。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"アクセラレーター論","era_start":2005,"schumpeter_layer":"メゾ","innovation_type":"組織・制度イノベーション","cognitive_mechanism":"集中指導と同期圧力による急成長","key_researchers":["Paul Graham","Jessica Livingston","Brad Feld"],"key_works":["Hackers and Painters (2004)","Startup Communities (2012)"],"keywords_ja":"Yコンビネーター,アクセラレーター,デモデー,シードプログラム","keywords_en":"Y Combinator,accelerator,demo day,seed program"},
  {"id":"inno_ent_227","name_ja":"Techstarsモデルと地域展開","name_en":"Techstars Model and Regional Expansion","definition":"Brad FeldとDavid Cohen等が2006年にコロラド州ボルダーで設立したアクセラレーター。YCとは異なりメンター駆動モデルを特徴とし、世界50都市以上で展開。企業連携プログラム（Techstars Industry Programs）を通じて大企業とのオープンイノベーションを媒介する。Brad Feldのボルダー・テーゼ（コミュニティ主導エコシステム）の実践的体現でもある。","impact_summary":"アクセラレーターモデルの地域・産業への水平展開を実証し、コーポレートアクセラレーションの先駆となった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"アクセラレーター論","era_start":2006,"schumpeter_layer":"メゾ","innovation_type":"組織・制度イノベーション","cognitive_mechanism":"メンターネットワークと集合知活用","key_researchers":["Brad Feld","David Cohen","Ian Hathaway"],"key_works":["Startup Communities (2012)","The Startup Community Way (2020)"],"keywords_ja":"Techstars,メンター主導,コーポレートアクセラレーター,ボルダー","keywords_en":"Techstars,mentor-driven,corporate accelerator,Boulder thesis"},
  {"id":"inno_ent_228","name_ja":"コーポレートアクセラレーターの設計","name_en":"Corporate Accelerator Design","definition":"大企業がスタートアップと連携するために設立する社内外アクセラレータープログラム。Microsoft Ventures、Google for Startups、Samsung NEXT等が代表例。戦略的目標（新規事業探索、技術獲得、市場創造）と財務リターンのバランス設計が重要課題。独立型vs社内型、完全所有vsパートナーシップ等の設計選択肢の効果が実証研究で検討されている。","impact_summary":"大企業のイノベーション戦略にスタートアップ連携を組み込む制度的形態を確立した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"コーポレートベンチャリング論","era_start":2010,"schumpeter_layer":"メゾ","innovation_type":"組織イノベーション","cognitive_mechanism":"大小組織間の文化的ブリッジング","key_researchers":["Markus Weiblen","Henry Chesbrough","Thomas Kohler"],"key_works":["Open Innovation with Large Firms (2015)","Corporate Accelerators: Building Bridges (2015)"],"keywords_ja":"コーポレートアクセラレーター,オープンイノベーション,大企業-スタートアップ連携","keywords_en":"corporate accelerator,open innovation,large firm-startup collaboration"},
  {"id":"inno_ent_229","name_ja":"社会的起業家精神のDees理論","name_en":"Dees Theory of Social Entrepreneurship","definition":"J. Gregory Deesが提唱した社会的起業家の定義：価値創造のための変革エージェントとして、機会認識・資源活用・継続的革新を通じて社会的変化を実現する者。Schumpeter的創造的破壊を社会問題解決に応用し、経済的持続可能性と社会的影響の両立を追求する。Grameen BankのMuhammad Yunusをモデルケースとして分析した。","impact_summary":"社会的起業家精神を独立した学術領域として確立し、social ventureとsocial innovationの研究基盤を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"社会的起業家論","era_start":1998,"schumpeter_layer":"ミクロ","innovation_type":"社会イノベーション","cognitive_mechanism":"社会的機会の認識と資源動員","key_researchers":["J. Gregory Dees","Roger Martin","Sally Osberg"],"key_works":["The Meaning of Social Entrepreneurship (1998)","Social Entrepreneurship: Making Sense of the Field (2007)"],"keywords_ja":"社会的起業家精神,Dees,変革エージェント,社会的価値","keywords_en":"social entrepreneurship,Dees,change agent,social value"},
  {"id":"inno_ent_230","name_ja":"Mair & Martí社会的起業家理論","name_en":"Mair and Marti Social Entrepreneurship Framework","definition":"Johanna MairとIgnasi Martíが提唱した社会的起業家精神の過程論的フレームワーク。社会的価値創造プロセスにおける機会認識→資源動員→組織化→社会変革の連鎖を記述し、制度的文脈（特に途上国）における社会的起業家の役割を分析した。「社会的起業家精神は機会の集合体」という命題を提示した。","impact_summary":"社会的起業家精神の過程論的理解を深め、制度的貧困地域での起業家研究の枠組みを提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"社会的起業家論","era_start":2006,"schumpeter_layer":"ミクロ","innovation_type":"社会イノベーション","cognitive_mechanism":"制度的文脈への適応と変革","key_researchers":["Johanna Mair","Ignasi Martí","Sucheta Nadkarni"],"key_works":["Social Entrepreneurship Research: A Source of Explanation (2006)","Entrepreneurship in and around Institutional Voids (2009)"],"keywords_ja":"社会的起業家精神,制度的空白,社会変革,過程論","keywords_en":"social entrepreneurship,institutional voids,social change,process theory"},
  {"id":"inno_ent_231","name_ja":"Zahra社会的起業家タイポロジー","name_en":"Zahra Social Entrepreneur Typology","definition":"Shaker ZahraらがDees理論を発展させ、社会的起業家を3類型に分類した：社会的起業家ブリコラー（地域資源活用）、社会的起業家コンストラクター（体系的変革）、社会的起業家エンジニア（革命的変革）。各類型の目標、資源利用戦略、影響スケールが異なり、支援戦略の差別化に寄与した。","impact_summary":"社会的起業家の多様性を類型化し、支援政策・研究設計の精緻化に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"社会的起業家論","era_start":2009,"schumpeter_layer":"ミクロ","innovation_type":"社会イノベーション","cognitive_mechanism":"タイプ別戦略的意図と影響スケール","key_researchers":["Shaker Zahra","Eric Gedajlovic","Donald Neubaum"],"key_works":["A Typology of Social Entrepreneurs (2009)"],"keywords_ja":"社会的起業家,タイポロジー,ブリコラー,コンストラクター","keywords_en":"social entrepreneur typology,bricoleur,constructionist,engineer"},
  {"id":"inno_ent_232","name_ja":"起業家的機会の発見vs創造論争","name_en":"Discovery vs Creation Debate in Entrepreneurial Opportunities","definition":"起業家的機会の存在論をめぐる中心的論争。発見観（Shane & Venkataraman）は機会が客観的に存在し起業家がそれを認識すると主張、創造観（Alvarez & Barney）は機会が起業家の行動によって作られると主張する。第三の立場としてHaberの解釈的アプローチ（機会は社会的に構築される）も提示されている。","impact_summary":"起業家的機会の存在論を深化させ、不確実性・リスク・機会評価の理論基盤を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"理論的イノベーション","cognitive_mechanism":"機会認識と社会的構築の相互作用","key_researchers":["Scott Shane","Sankaran Venkataraman","Sharon Alvarez","Jay Barney"],"key_works":["The Promise of Entrepreneurship as a Field of Research (2000)","Discovery and Creation: Alternative Theories of Entrepreneurial Action (2007)"],"keywords_ja":"起業家的機会,発見vs創造,機会認識,存在論","keywords_en":"entrepreneurial opportunity,discovery vs creation,opportunity recognition,ontology"},
  {"id":"inno_ent_233","name_ja":"起業家的機会の第三の道","name_en":"Third View of Entrepreneurial Opportunities","definition":"Ramoglou & TseとSarason等が提唱した、発見論と創造論のどちらにも還元されない第三の立場。機会は可能性として潜在的に存在するが、起業家の解釈・行動・文脈との相互作用によって実現されるという「アクチュアリゼーション」概念を中核とする。批判的実在論の枠組みを起業家研究に適用した。","impact_summary":"機会研究の哲学的基盤を刷新し、プロセス的・関係的起業家論の発展に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":2015,"schumpeter_layer":"ミクロ","innovation_type":"理論的イノベーション","cognitive_mechanism":"可能性のアクチュアリゼーションと起業家的判断","key_researchers":["Stratos Ramoglou","Eric Tsang","Yolanda Sarason"],"key_works":["Eliminating the Discovery/Creation Debate (2016)","Opportunity, Perception and Enactment (2006)"],"keywords_ja":"起業家的機会,第三の立場,アクチュアリゼーション,批判的実在論","keywords_en":"entrepreneurial opportunity,third view,actualization,critical realism"},
  {"id":"inno_ent_234","name_ja":"起業家的失敗と学習研究","name_en":"Entrepreneurial Failure and Learning","definition":"スタートアップの失敗率（設立後5年で約50%）とその原因・学習効果を研究する領域。Dean Shepherd（Grief Theory of Entrepreneurial Failure）は感情的苦痛と学習の関係を分析し、喪失経験の処理が次の起業成功に影響することを示した。シリコンバレーの「失敗祭（FailCon）」に代表される失敗を肯定する文化と、その欠如が起業家精神に与える影響も研究されている。","impact_summary":"失敗を学習リソースとして位置づける視点を提供し、起業家教育と政策設計に応用された。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"行動的起業家論","era_start":2003,"schumpeter_key":"ミクロ","schumpeter_layer":"ミクロ","innovation_type":"行動・認知イノベーション","cognitive_mechanism":"喪失感情の処理と経験からの学習","key_researchers":["Dean Shepherd","Johan Wiklund","Melissa Cardon"],"key_works":["Learning from Business Failure (2003)","Moving Forward from Project Failure (2011)"],"keywords_ja":"起業失敗,学習,喪失感情,シリアル起業家","keywords_en":"entrepreneurial failure,learning,grief theory,serial entrepreneurship"},
  {"id":"inno_ent_235","name_ja":"シリアル起業家と成功確率","name_en":"Serial Entrepreneurship and Success Probability","definition":"複数回の起業経験を持つシリアル起業家の研究。Paul Gompers等のHBS研究（2010）によれば、過去成功経験のある起業家は再起業時の成功確率が有意に高いが、過去失敗経験者の成功率は初回起業家とほぼ変わらないという「成功の持続性」発見が重要。その一方でBraz Camargo等は失敗から固有の学習が起きると主張する。","impact_summary":"起業経験の価値を実証し、シリアル起業家支援政策と投資判断の根拠を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"行動的起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"実証的イノベーション研究","cognitive_mechanism":"経験からの選択的学習と自己効力感","key_researchers":["Paul Gompers","Anna Kovner","Josh Lerner"],"key_works":["Performance Persistence in Entrepreneurship (2010)","Serial Entrepreneurs: Picks and Shovels (2016)"],"keywords_ja":"シリアル起業家,成功確率,学習効果,ポートフォリオ","keywords_en":"serial entrepreneurship,success probability,performance persistence,portfolio"},
  {"id":"inno_ent_236","name_ja":"家族企業のイノベーション特性","name_en":"Family Business Innovation Characteristics","definition":"家族が支配株主・経営者として関与する企業（全世界企業の70〜80%）のイノベーション行動の特性研究。Andersonら（2003）のEntrenched Controllerとして長期投資を促す機能と、Pollak（1985）のファミリーモデルによる効率的ガバナンスの両面が研究されている。SEW（Socioemotional Wealth）理論は家族企業が経済的利益より感情的価値を優先する傾向を説明する。","impact_summary":"家族企業の独自イノベーション論理を解明し、後継者育成・IPO・M&A戦略の理論基盤となった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"家族企業論","era_start":2003,"schumpeter_layer":"ミクロ","innovation_type":"組織イノベーション","cognitive_mechanism":"SEW（社会感情的富）と長期志向","key_researchers":["Ronald Anderson","David Reeb","Luis Gomez-Mejia"],"key_works":["Founding-Family Ownership (2003)","Socioemotional Wealth and Corporate Responses (2010)"],"keywords_ja":"家族企業,SEW,イノベーション,長期志向,後継","keywords_en":"family business,socioemotional wealth,innovation,long-term orientation,succession"},
  {"id":"inno_ent_237","name_ja":"フランチャイズとイノベーション普及","name_en":"Franchising as Innovation Diffusion","definition":"フランチャイズシステムをビジネスモデルの標準化・複製・普及メカニズムとして分析する研究領域。Oxenfeldtら（1969）のResource Scarcity理論から、Rubin（1978）のインセンティブ整合理論を経て、Combs & Ketchenの能力論的フランチャイズ研究まで発展。フランチャイジーによるローカル適応イノベーションが本部へ逆流するReverse Innovationも研究されている。","impact_summary":"ビジネスモデルの地理的複製と標準化を理論化し、グローバル展開戦略の研究基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"フランチャイズ論","era_start":1969,"schumpeter_layer":"メゾ","innovation_type":"ビジネスモデルイノベーション","cognitive_mechanism":"ナレッジ移転と局所適応の均衡","key_researchers":["Shelby Hunt","James Combs","Gary Castrogiovanni"],"key_works":["The Nature and Scope of Franchising (1977)","Franchising: A Review and Avenues to Greater Theoretical Diversity (2004)"],"keywords_ja":"フランチャイズ,ビジネスモデル複製,逆イノベーション,標準化","keywords_en":"franchising,business model replication,reverse innovation,standardization"},
  {"id":"inno_ent_238","name_ja":"起業家的チームの構成と成果","name_en":"Entrepreneurial Team Composition and Performance","definition":"単独起業家より多くの場合にチームで立ち上げられるベンチャーにおける、チーム構成・ダイナミクス・意思決定の研究。機能的多様性（技術×営業×財務の補完）、認知的多様性、先行経験の重複度が成果に与える影響が分析される。創業者間の株式配分・役割分担・意見対立の解消プロセスも重要研究テーマ。Eisenhardt & Schoonhovenらの高速成長チーム研究が先駆的。","impact_summary":"「チームが最重要資産」というVC格言を実証的に支持し、創業チーム設計の知見を蓄積した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"チーム起業家論","era_start":1996,"schumpeter_layer":"ミクロ","innovation_type":"組織イノベーション","cognitive_mechanism":"認知的多様性と創造的摩擦","key_researchers":["Kathleen Eisenhardt","Claudia Bird Schoonhoven","Melissa Cardon"],"key_works":["Resource-based View of Strategic Alliance Formation (1996)","Founding Teams' Human Capital and New Venture Growth (2006)"],"keywords_ja":"起業チーム,チーム構成,機能的多様性,株式配分","keywords_en":"entrepreneurial team,team composition,functional diversity,equity split"},
  {"id":"inno_ent_239","name_ja":"起業とジェンダー：参入障壁","name_en":"Gender and Entrepreneurship: Entry Barriers","definition":"女性起業家が直面する構造的・認知的・資本的参入障壁の研究。資金調達格差（女性創業者は男性の約3%しかVCを獲得しない：Diversity VC 2019データ）、ネットワーク排除（「Bro Culture」）、リスク認知の性差、ロールモデル不足等が記録されている。Candida Brush等による女性起業家研究の蓄積が政策提言の基盤となっている。","impact_summary":"ジェンダー格差の実証により、女性起業家支援政策の根拠を提供し、エコシステムの包摂性議論を活性化した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"フェミニスト起業家論","era_start":1992,"schumpeter_layer":"ミクロ","innovation_type":"社会的イノベーション","cognitive_mechanism":"社会的アイデンティティと起業意図","key_researchers":["Candida Brush","Diana Hechavarria","Sophie Manigart"],"key_works":["A Gender-Aware Framework for Women's Entrepreneurship (2009)","Gatekeepers of Venture Growth (2018)"],"keywords_ja":"女性起業家,ジェンダーギャップ,VC格差,参入障壁","keywords_en":"women entrepreneurship,gender gap,VC disparity,entry barriers"},
  {"id":"inno_ent_240","name_ja":"起業とジェンダー：パフォーマンス差異","name_en":"Gender and Entrepreneurship: Performance Differences","definition":"女性と男性の起業家のパフォーマンス（成長率、収益性、生存率）の差異とその原因の実証研究。Watson（2002）等の研究は規模・業種を統制すると性差は縮小することを示したが、Robb & Watson（2012）はリスク選好・成長志向の違いが業績差を生むと論じた。社会化・教育・資本アクセスの歴史的差異が原因として指摘されている。","impact_summary":"パフォーマンス差異の実証が女性起業家支援プログラムの設計改善に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"フェミニスト起業家論","era_start":2002,"schumpeter_layer":"ミクロ","innovation_type":"実証的イノベーション研究","cognitive_mechanism":"リスク選好と成長志向の性差","key_researchers":["John Watson","Alicia Robb","David Robinson"],"key_works":["Comparing the Performance of Male and Female Controlled Businesses (2002)","Gender, Risk, and Venture Success (2012)"],"keywords_ja":"女性起業家,パフォーマンス差異,リスク選好,成長志向","keywords_en":"women entrepreneurship,performance gap,risk preference,growth orientation"},
  {"id":"inno_ent_241","name_ja":"ハイテクスタートアップの成長モデル","name_en":"High-Tech Startup Growth Models","definition":"テクノロジースタートアップが採用する成長戦略の研究。ウイルス係数（K-factor）に基づくバイラル成長、製品主導成長（PLG）、販売主導成長（SLG）の3類型が基本。Blitzscaling（Reid Hoffman）はネットワーク効果市場での速度優先成長理論を提唱し、効率性より市場制覇速度を最大化する。コホート分析、LTV/CAC比率、NRR（Net Revenue Retention）が成長の健全性指標となる。","impact_summary":"高速成長スタートアップの経営管理理論を整備し、SaaS・マーケットプレイス等の成長最適化の実務基盤となった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2014,"schumpeter_layer":"ミクロ","innovation_type":"成長戦略イノベーション","cognitive_mechanism":"ネットワーク効果と規模の経済の活用","key_researchers":["Reid Hoffman","Chris Yeh","Andrew Chen"],"key_works":["Blitzscaling (2018)","The Cold Start Problem (2021)"],"keywords_ja":"ハイテクスタートアップ,ブリッツスケーリング,PLG,バイラル成長","keywords_en":"high-tech startup,blitzscaling,PLG,viral growth"},
  {"id":"inno_ent_242","name_ja":"ユニコーン企業の分析","name_en":"Unicorn Company Analysis","definition":"Aileen Lee（2013）が命名した企業価値10億ドル超の未上場スタートアップ（ユニコーン）の特性・生成条件・エコシステム要因の研究。2013年時点で39社だったが2022年には1,000社超に急増。ネットワーク効果・スケーラビリティ・データ独占・プラットフォーム性が共通的成功要因として特定されている。CB InsightsのUnicorn Trackerが主要データソース。","impact_summary":"超高成長スタートアップの条件を実証的に特定し、投資家・政策立案者・起業家の目標設定に影響した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2013,"schumpeter_layer":"メゾ","innovation_type":"企業価値イノベーション","cognitive_mechanism":"ネットワーク効果と独占的地位の形成","key_researchers":["Aileen Lee","Ilya Strebulaev","Alex Dang"],"key_works":["Welcome to the Unicorn Club (2013)","How Do Venture Capitalists Make Decisions? (2020)"],"keywords_ja":"ユニコーン,企業価値,ネットワーク効果,CB Insights","keywords_en":"unicorn,enterprise value,network effects,CB Insights"},
  {"id":"inno_ent_243","name_ja":"デカコーンとスタートアップ経済学","name_en":"Decacorn and Startup Economics","definition":"企業価値100億ドル超の未上場スタートアップ（デカコーン）の経済的・制度的含意の研究。Stripe、SpaceX、ByteDance等が代表例。Late-stage private investorsとしてのSoftBank Vision Fund、タイガーグローバル等のクロスオーバー投資家が形成する「プライベートIPO」現象が分析される。株式流動性の欠如と個人投資家の排除が制度課題として議論されている。","impact_summary":"プライベート市場の巨大化がパブリック市場の価値発見機能に与える影響を問い直す研究を促進した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"コーポレートファイナンス論","era_start":2015,"schumpeter_layer":"メゾ","innovation_type":"金融市場イノベーション","cognitive_mechanism":"流動性プレミアムと長期保有インセンティブ","key_researchers":["Ilya Strebulaev","Will Gornall","Masayoshi Son"],"key_works":["Squaring Venture Capital Valuations with Reality (2020)","SoftBank Vision Fund Story (2019)"],"keywords_ja":"デカコーン,クロスオーバー投資,プライベート市場,Vision Fund","keywords_en":"decacorn,crossover investors,private market,Vision Fund"},
  {"id":"inno_ent_244","name_ja":"起業家的認知理論","name_en":"Entrepreneurial Cognition Theory","definition":"起業家の意思決定・機会評価・リスク判断を認知科学の視点から分析する研究領域。Mitchell et al.（2002）は「起業家的認知スキーマ」として手配（arrangements）・意欲（willingness）・能力（ability）の3要素を提唱。認知バイアス（過信、楽観性、管理可能性錯覚）が起業成果に与える影響も重要研究テーマ。Baron（1998）の認知的・感情的側面の統合研究が先駆的。","impact_summary":"起業家行動の心理的基盤を解明し、起業家教育における認知訓練プログラムの設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":1998,"schumpeter_layer":"ミクロ","innovation_type":"認知・行動イノベーション","cognitive_mechanism":"スキーマ形成と認知バイアスの相互作用","key_researchers":["Ronald Baron","Robert Mitchell","Melissa Cardon"],"key_works":["Cognitive Mechanisms in Entrepreneurship (1998)","Toward a Theory of the Entrepreneurial Cognitions (2002)"],"keywords_ja":"起業家的認知,スキーマ,認知バイアス,過信","keywords_en":"entrepreneurial cognition,schema,cognitive bias,overconfidence"},
  {"id":"inno_ent_245","name_ja":"起業家的アイデンティティ理論","name_en":"Entrepreneurial Identity Theory","definition":"起業家としての自己概念（アイデンティティ）の形成・維持・変容プロセスの研究。Cardon et al.（2009）は起業家的情熱（entrepreneurial passion）を特定の役割アイデンティティ（発明家・創業者・開発者）への強い同一化として定式化した。役割ストレス、アイデンティティ競合（「起業家vs親」等）、失敗後のアイデンティティ再構築も研究されている。","impact_summary":"起業家の動機・継続意志・回復力を説明する枠組みを提供し、起業支援の心理的側面の理解に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":2009,"schumpeter_layer":"ミクロ","innovation_type":"アイデンティティ・動機イノベーション","cognitive_mechanism":"役割アイデンティティの中央性と情熱","key_researchers":["Melissa Cardon","Christopher Zietsma","Patricia Saparito"],"key_works":["The Nature and Experience of Entrepreneurial Passion (2009)","A Tale of Passion (2005)"],"keywords_ja":"起業家アイデンティティ,情熱,役割理論,自己概念","keywords_en":"entrepreneurial identity,passion,role theory,self-concept"},
  {"id":"inno_ent_246","name_ja":"起業家的志向性（EO）","name_en":"Entrepreneurial Orientation","definition":"Miller（1983）とLumpkin & Dess（1996）が体系化した組織レベルの起業家的行動傾向の構成概念。革新性（innovativeness）、リスクテイキング（risk-taking）、先見性（proactiveness）の3次元（後に自律性・競争的攻撃性を追加）でEOを測定する尺度が広く使用される。中小企業・新興企業のパフォーマンスとEOの関係が多数の国際比較研究で検証されている。","impact_summary":"組織レベルの起業家精神を測定可能な構成概念として確立し、800件以上の実証研究の基盤となった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"戦略的起業家論","era_start":1983,"schumpeter_layer":"ミクロ","innovation_type":"組織イノベーション","cognitive_mechanism":"組織的リスク選好と先見的行動","key_researchers":["Danny Miller","G.T. Lumpkin","Gregory Dess"],"key_works":["The Correlates of Entrepreneurship (1983)","Clarifying the Entrepreneurial Orientation Construct (1996)"],"keywords_ja":"起業家的志向性,EO,リスクテイキング,先見性,革新性","keywords_en":"entrepreneurial orientation,EO,risk-taking,proactiveness,innovativeness"},
  {"id":"inno_ent_247","name_ja":"コーポレートベンチャリング理論","name_en":"Corporate Venturing Theory","definition":"既存大企業が新規事業を創出するプロセスと組織形態の研究。内部コーポレートベンチャリング（社内起業）、JVスピンオフ、戦略的VC投資（CVC）の3形態が分類される。Robert Burgelman（1983）の自律的vs誘導的戦略プロセスモデルが理論基盤。既存事業（exploitation）と新規探索（exploration）の緊張関係、「組織の免疫」による新規事業の排除メカニズムも研究される。","impact_summary":"大企業の起業家的更新メカニズムを理論化し、イントラプレナーシップ（社内起業家制度）設計の基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"コーポレートベンチャリング論","era_start":1983,"schumpeter_layer":"メゾ","innovation_type":"組織イノベーション","cognitive_mechanism":"組織的探索と既存事業の利益相反","key_researchers":["Robert Burgelman","Ian MacMillan","Rita McGrath"],"key_works":["Corporate Venturing (1986)","Discovery-Driven Planning (1995)"],"keywords_ja":"コーポレートベンチャリング,社内起業,CVC,イントラプレナー","keywords_en":"corporate venturing,intrapreneurship,CVC,internal startup"},
  {"id":"inno_ent_248","name_ja":"CVC（コーポレートベンチャーキャピタル）","name_en":"Corporate Venture Capital","definition":"事業会社がスタートアップへの直接投資を行うCVC部門の研究。Google Ventures（GV）、Intel Capital、Salesforce Venturesが代表例。独立VCと比較して財務リターンより戦略的リターン（技術情報取得・新規市場探索）を重視する傾向が確認されている。CVCの投資先スタートアップは独立VC支援企業よりIPO後の長期パフォーマンスが高い（Chemmanur et al.2014）という実証もある。","impact_summary":"大企業がスタートアップエコシステムに統合される制度的形態を確立し、オープンイノベーションの資本側を担った。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"コーポレートベンチャリング論","era_start":1990,"schumpeter_layer":"メゾ","innovation_type":"金融・組織イノベーション","cognitive_mechanism":"戦略的オプション価値と財務リターンの均衡","key_researchers":["Thomas Chemmanur","Elena Loutskina","Xuan Tian"],"key_works":["Corporate Venture Capital, Value Creation, and Innovation (2014)","CVC and Its Role in Innovation (2017)"],"keywords_ja":"CVC,コーポレートVC,戦略的投資,Intel Capital","keywords_en":"CVC,corporate VC,strategic investment,Intel Capital"},
  {"id":"inno_ent_249","name_ja":"移民起業家精神の理論","name_en":"Immigrant Entrepreneurship Theory","definition":"移民起業家の経済的編入と起業行動の理論研究。ライトハウス移民（lighthouse immigrants）の機会発見能力、エスニックビジネス（エスニック市場への特化）、移民エンクレーブの役割が分析される。Portes & Bachの「社会関係資本としての民族的絆」理論と、Saxenianの「シリコンバレーにおけるアジア系起業家ネットワーク」研究が代表的。","impact_summary":"移民が経済的活力と技術革新の主要な源泉であることを実証し、移民政策と起業家政策の接点を作った。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"移民起業家論","era_start":1995,"schumpeter_layer":"ミクロ","innovation_type":"社会・文化イノベーション","cognitive_mechanism":"文化的橋渡しと機会認識の移民的優位","key_researchers":["Alejandro Portes","AnnaLee Saxenian","Vivek Wadhwa"],"key_works":["The Immigrant Divide (2011)","Silicon Valley's New Immigrant Entrepreneurs (1999)"],"keywords_ja":"移民起業家,エスニックビジネス,社会関係資本,シリコンバレー","keywords_en":"immigrant entrepreneurship,ethnic business,social capital,Silicon Valley"},
  {"id":"inno_ent_250","name_ja":"農村・地方起業家精神","name_en":"Rural and Regional Entrepreneurship","definition":"都市部とは異なる地理的・制度的・資本的条件下での農村・地方起業家精神の研究。Stathopoulou et al.（2004）は農村起業家の特徴として地域資源活用、社会的組込み（social embeddedness）、多様な動機（生活様式選択を含む）を挙げた。デジタル化（リモートワーク・EC）が農村起業家の条件を変えつつある近年の動向も研究されている。","impact_summary":"都市偏重の起業家研究を批判的に拡張し、地方創生・農村活性化政策の理論的根拠を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"地域起業家論","era_start":2004,"schumpeter_layer":"メゾ","innovation_type":"地域社会イノベーション","cognitive_mechanism":"地域資源の再結合と場所へのアタッチメント","key_researchers":["Sara Stathopoulou","David Smallbone","Friederike Welter"],"key_works":["Rural Entrepreneurship in Britain (2004)","Contextualizing Entrepreneurship (2011)"],"keywords_ja":"農村起業家精神,地方創生,社会的組込み,デジタル化","keywords_en":"rural entrepreneurship,regional development,social embeddedness,digitalization"},
]

conn = sqlite3.connect(DB_PATH)
c = conn.cursor()

inserted = 0
skipped = 0
for r in records:
    try:
        c.execute("""INSERT INTO innovation_theory
            (id,name_ja,name_en,definition,impact_summary,subfield,category,
             school_of_thought,era_start,schumpeter_layer,innovation_type,
             cognitive_mechanism,key_researchers,key_works,keywords_ja,keywords_en)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (r["id"],r["name_ja"],r["name_en"],r["definition"],r["impact_summary"],
             r["subfield"],r["category"],r["school_of_thought"],r["era_start"],
             r["schumpeter_layer"],r["innovation_type"],r["cognitive_mechanism"],
             json.dumps(r["key_researchers"],ensure_ascii=False),
             json.dumps(r["key_works"],ensure_ascii=False),
             r["keywords_ja"],r["keywords_en"]))
        inserted += 1
    except sqlite3.IntegrityError:
        skipped += 1

conn.commit()
conn.close()
print(f"Inserted: {inserted}, Skipped: {skipped}")

